    def test_local_csv_query_builder_schema_quality_helpers_invoke_sql_smoke(self) -> None:
        binary = self.fake_cli(
            textwrap.dedent(
                """
                import json, sys

                assert sys.argv[1:] == [
                    "local-source-runtime",
                    "SELECT id,label,amount FROM 'target/input.csv' WHERE amount >= 10 LIMIT 100",
                    "--output-format",
                    "inline-jsonl",
                    "--format",
                    "json",
                ], sys.argv
                print(json.dumps({
                    "schema_version": "shardloom.output.v2",
                    "command": "local-source-runtime",
                    "status": "success",
                    "summary": "sql local source",
                    "human_text": "sql local source",
                    "fallback": {"attempted": False, "allowed": False, "engine": None, "reason": "disabled"},
                    "diagnostics": [],
                    "fields": [
                        {"key": "result_jsonl", "value": "{\\"id\\":1,\\"label\\":\\"alpha\\",\\"amount\\":10}\\n{\\"id\\":2,\\"label\\":null,\\"amount\\":15}\\n{\\"id\\":3,\\"label\\":\\"alpha\\",\\"amount\\":21}\\n"},
                        {"key": "output_row_count", "value": "3"},
                        {"key": "selected_row_count", "value": "3"},
                        {"key": "user_surface_runtime_scope", "value": "format_neutral_sql_frontend"},
                        {"key": "format_specific_boundary_scope", "value": "read_adapter_and_write_sink_only"},
                        {"key": "format_specific_compute_path", "value": "false"},
                        {"key": "fallback_attempted", "value": "false"},
                        {"key": "external_engine_invoked", "value": "false"},
                        {"key": "claim_gate_status", "value": "fixture_smoke_only"}
                    ],
                }))
                """
            )
        )
        ctx = ShardLoomContext(ShardLoomClient(binary=binary))
        workflow = (
            ctx.read_csv("target/input.csv")
            .select("id", "label", "amount")
            .filter(sl.col("amount") >= 10)
        )

        schema = workflow.schema()
        described = workflow.describe_schema()
        validation = workflow.validate_schema(
            {"id": "int64", "label": "string", "amount": "int64"}
        )
        contract = workflow.schema_contract(
            {"id": "int64", "label": "string", "amount": "int64"}
        )
        quality_summary = workflow.data_quality_summary()
        quality_checks = workflow.data_quality_check(
            "not_null:id",
            "not_null:label",
            "unique:id",
            "unique:label",
            "regex:label:^a",
        )
        profile = workflow.profile()
        quarantine = workflow.quarantine(None, "not_null:label")

        self.assertIsInstance(schema, sl.WorkflowSchemaReport)
        self.assertEqual(schema.schema_map, {"id": "int64", "label": "utf8", "amount": "int64"})
        self.assertEqual(schema.field("label").null_count, 1)
        self.assertEqual(schema.nullable_fields, ("label",))
        self.assertFalse(schema.fallback_attempted)
        self.assertFalse(schema.external_engine_invoked)
        self.assertEqual(described.field_names, ("id", "label", "amount"))
        self.assertTrue(validation.valid)
        self.assertTrue(contract.valid)
        self.assertFalse(contract.fallback_attempted)
        self.assertFalse(contract.external_engine_invoked)
        self.assertEqual(validation.dtype_mismatches, ())
        self.assertEqual(quality_summary.null_counts, {"id": 0, "label": 1, "amount": 0})
        self.assertEqual(quality_summary.row_count, 3)
        self.assertFalse(quality_checks.passed)
        by_check = {result.check: result for result in quality_checks.checks}
        self.assertTrue(by_check["not_null:id"].passed)
        self.assertFalse(by_check["not_null:label"].passed)
        self.assertEqual(by_check["not_null:label"].failing_row_count, 1)
        self.assertTrue(by_check["unique:id"].passed)
        self.assertFalse(by_check["unique:label"].passed)
        self.assertEqual(by_check["unique:label"].failing_row_count, 1)
        self.assertFalse(by_check["regex:label:^a"].passed)
        self.assertEqual(by_check["regex:label:^a"].failing_row_count, 1)
        self.assertIsInstance(profile, sl.WorkflowProfileReport)
        self.assertEqual(profile.profile_kind, "bounded_local_source_runtime_profile")
        self.assertEqual(profile.materialization_boundary, "bounded_inline_jsonl_profile")
        self.assertEqual(profile.limit, 100)
        self.assertEqual(profile.row_count, 3)
        self.assertEqual(profile.field_count, 3)
        self.assertEqual(profile.null_counts, {"id": 0, "label": 1, "amount": 0})
        self.assertTrue(profile.runtime_execution)
        self.assertTrue(profile.data_read)
        self.assertFalse(profile.write_io)
        self.assertFalse(profile.fallback_attempted)
        self.assertFalse(profile.external_engine_invoked)
        self.assertIsInstance(quarantine, sl.WorkflowQuarantineReport)
        self.assertEqual(quarantine.quarantine_policy, "bounded_local_source_quarantine.v1")
        self.assertEqual(quarantine.quarantine_status, "report_only")
        self.assertEqual(quarantine.quarantined_row_count, 1)
        self.assertEqual(quarantine.rows, ({"id": 2, "label": None, "amount": 15},))
        self.assertFalse(quarantine.write_io)
        self.assertFalse(quarantine.fallback_attempted)
        self.assertFalse(quarantine.external_engine_invoked)

    def test_local_csv_query_builder_quarantine_writes_pushdown_not_null_rows(self) -> None:
        base = "SELECT id,label,amount FROM 'target/input.csv' WHERE amount >= 10"
        quarantine_statement = (
            "SELECT id,label,amount FROM 'target/input.csv' "
            "WHERE (amount >= 10) AND (label IS NULL) LIMIT 100"
        )
        binary = self.fake_cli(
            textwrap.dedent(
                f"""
                import json, sys

                assert sys.argv[1] == "local-source-runtime", sys.argv
                statement = sys.argv[2]
                if statement == {base + " LIMIT 100"!r}:
                    assert sys.argv[3:] == [
                        "--output-format",
                        "inline-jsonl",
                        "--format",
                        "json",
                    ], sys.argv
                    result_jsonl = "{{\\"id\\":1,\\"label\\":\\"alpha\\",\\"amount\\":10}}\\n{{\\"id\\":2,\\"label\\":null,\\"amount\\":15}}\\n{{\\"id\\":3,\\"label\\":\\"alpha\\",\\"amount\\":21}}\\n"
                    output_path = None
                    output_format = "inline-jsonl"
                    row_count = "3"
                elif statement == {quarantine_statement!r}:
                    assert sys.argv[3:] == [
                        "--output-format",
                        "jsonl",
                        "--output",
                        "target/bad.jsonl",
                        "--allow-overwrite",
                        "--format",
                        "json",
                    ], sys.argv
                    result_jsonl = "{{\\"id\\":2,\\"label\\":null,\\"amount\\":15}}\\n"
                    output_path = "target/bad.jsonl"
                    output_format = "jsonl"
                    row_count = "1"
                else:
                    raise AssertionError(sys.argv)
                fields = [
                    {{"key": "result_jsonl", "value": result_jsonl}},
                    {{"key": "output_row_count", "value": row_count}},
                    {{"key": "selected_row_count", "value": row_count}},
                    {{"key": "output_format", "value": output_format}},
                    {{"key": "fallback_attempted", "value": "false"}},
                    {{"key": "external_engine_invoked", "value": "false"}},
                    {{"key": "claim_gate_status", "value": "fixture_smoke_only"}},
                ]
                if output_path is not None:
                    fields.extend([
                        {{"key": "output_path", "value": output_path}},
                        {{"key": "output_io_performed", "value": "true"}},
                        {{"key": "output_commit_status", "value": "committed"}},
                        {{"key": "output_native_io_certificate_status", "value": "certified_local_jsonl_sink"}},
                        {{"key": "result_replay_verified", "value": "true"}},
                    ])
                print(json.dumps({{
                    "schema_version": "shardloom.output.v2",
                    "command": "local-source-runtime",
                    "status": "success",
                    "summary": "sql local source",
                    "human_text": "sql local source",
                    "fallback": {{"attempted": False, "allowed": False, "engine": None, "reason": "disabled"}},
                    "diagnostics": [],
                    "fields": fields,
                }}))
                """
            )
        )
        ctx = ShardLoomContext(ShardLoomClient(binary=binary))
        workflow = (
            ctx.read_csv("target/input.csv")
            .select("id", "label", "amount")
            .filter(sl.col("amount") >= 10)
        )

        report = workflow.quarantine(
            "target/bad.jsonl",
            "not_null:label",
            output_format="jsonl",
            allow_overwrite=True,
        )

        self.assertIsInstance(report, sl.WorkflowQuarantineReport)
        self.assertEqual(report.quarantine_status, "written")
        self.assertEqual(report.quarantined_row_count, 1)
        self.assertEqual(report.output_path, "target/bad.jsonl")
        self.assertEqual(report.output_format, "jsonl")
        self.assertEqual(report.output_commit_status, "committed")
        self.assertEqual(
            report.output_native_io_certificate_status,
            "certified_local_jsonl_sink",
        )
        self.assertTrue(report.result_replay_verified)
        self.assertTrue(report.runtime_execution)
        self.assertTrue(report.data_read)
        self.assertTrue(report.write_io)
        self.assertFalse(report.fallback_attempted)
        self.assertFalse(report.external_engine_invoked)

    def test_local_csv_query_builder_quarantine_writes_pushdown_regex_rows(self) -> None:
        base = "SELECT id,label,amount FROM 'target/input.csv' WHERE amount >= 10"
        quarantine_statement = (
            "SELECT id,label,amount FROM 'target/input.csv' "
            "WHERE (amount >= 10) AND ((label IS NULL OR label NOT RLIKE '^a')) LIMIT 100"
        )
        binary = self.fake_cli(
            textwrap.dedent(
                f"""
                import json, sys

                assert sys.argv[1] == "local-source-runtime", sys.argv
                statement = sys.argv[2]
                if statement == {base + " LIMIT 100"!r}:
                    assert sys.argv[3:] == [
                        "--output-format",
                        "inline-jsonl",
                        "--format",
                        "json",
                    ], sys.argv
                    result_jsonl = "{{\\"id\\":1,\\"label\\":\\"alpha\\",\\"amount\\":10}}\\n{{\\"id\\":2,\\"label\\":\\"beta\\",\\"amount\\":15}}\\n{{\\"id\\":3,\\"label\\":null,\\"amount\\":21}}\\n"
                    output_path = None
                    output_format = "inline-jsonl"
                    row_count = "3"
                elif statement == {quarantine_statement!r}:
                    assert sys.argv[3:] == [
                        "--output-format",
                        "jsonl",
                        "--output",
                        "target/regex-bad.jsonl",
                        "--allow-overwrite",
                        "--format",
                        "json",
                    ], sys.argv
                    result_jsonl = "{{\\"id\\":2,\\"label\\":\\"beta\\",\\"amount\\":15}}\\n{{\\"id\\":3,\\"label\\":null,\\"amount\\":21}}\\n"
                    output_path = "target/regex-bad.jsonl"
                    output_format = "jsonl"
                    row_count = "2"
                else:
                    raise AssertionError(sys.argv)
                fields = [
                    {{"key": "result_jsonl", "value": result_jsonl}},
                    {{"key": "output_row_count", "value": row_count}},
                    {{"key": "selected_row_count", "value": row_count}},
                    {{"key": "output_format", "value": output_format}},
                    {{"key": "fallback_attempted", "value": "false"}},
                    {{"key": "external_engine_invoked", "value": "false"}},
                    {{"key": "claim_gate_status", "value": "fixture_smoke_only"}},
                ]
                if output_path is not None:
                    fields.extend([
                        {{"key": "output_path", "value": output_path}},
                        {{"key": "output_io_performed", "value": "true"}},
                        {{"key": "output_commit_status", "value": "committed"}},
                        {{"key": "output_native_io_certificate_status", "value": "certified_local_jsonl_sink"}},
                        {{"key": "result_replay_verified", "value": "true"}},
                    ])
                print(json.dumps({{
                    "schema_version": "shardloom.output.v2",
                    "command": "local-source-runtime",
                    "status": "success",
                    "summary": "sql local source",
                    "human_text": "sql local source",
                    "fallback": {{"attempted": False, "allowed": False, "engine": None, "reason": "disabled"}},
                    "diagnostics": [],
                    "fields": fields,
                }}))
                """
            )
        )
        ctx = ShardLoomContext(ShardLoomClient(binary=binary))
        workflow = (
            ctx.read_csv("target/input.csv")
            .select("id", "label", "amount")
            .filter(sl.col("amount") >= 10)
        )

        quality = workflow.data_quality_check("matches:label:^a")
        report = workflow.quarantine(
            "target/regex-bad.jsonl",
            "regex:label:^a",
            output_format="jsonl",
            allow_overwrite=True,
        )

        self.assertIsInstance(quality, sl.WorkflowDataQualityReport)
        by_check = {result.check: result for result in quality.checks}
        self.assertFalse(by_check["matches:label:^a"].passed)
        self.assertEqual(by_check["matches:label:^a"].failing_row_count, 2)
        self.assertIsInstance(report, sl.WorkflowQuarantineReport)
        self.assertEqual(report.quarantine_status, "written")
        self.assertEqual(report.quarantined_row_count, 2)
        self.assertEqual(report.output_path, "target/regex-bad.jsonl")
        self.assertEqual(report.output_format, "jsonl")
        self.assertEqual(report.output_commit_status, "committed")
        self.assertTrue(report.result_replay_verified)
        self.assertTrue(report.runtime_execution)
        self.assertTrue(report.data_read)
        self.assertTrue(report.write_io)
        self.assertFalse(report.fallback_attempted)
        self.assertFalse(report.external_engine_invoked)

    def test_local_csv_query_builder_malformed_regex_quality_and_quarantine_are_unsupported(
        self,
    ) -> None:
        binary = self.fake_cli(
            textwrap.dedent(
                """
                import json, sys

                assert sys.argv[1] == "workflow-unsupported-plan", sys.argv
                operation = sys.argv[2]
                assert operation in {"data-quality", "quarantine"}, sys.argv
                assert sys.argv[3:] == [
                    "read_csv(target/input.csv) -> select(id,label)",
                    "regex:label:[",
                    "--format",
                    "json",
                ], sys.argv
                print(json.dumps({
                    "schema_version": "shardloom.output.v2",
                    "command": "workflow-unsupported-plan",
                    "status": "unsupported",
                    "summary": "unsupported",
                    "human_text": "unsupported",
                    "fallback": {"attempted": False, "allowed": False, "engine": None, "reason": "disabled"},
                    "diagnostics": [{
                        "code": "SL_NOT_IMPLEMENTED",
                        "severity": "error",
                        "category": "unsupported_feature",
                        "message": "unsupported",
                        "feature": f"cg21.workflow.{operation}",
                        "reason": "regex quality rule is not admitted",
                        "suggested_next_step": "inspect capability and evidence reports",
                        "fallback": {"attempted": False, "allowed": False, "engine": None, "reason": "disabled"}
                    }],
                    "fields": [
                        {"key": "workflow_operation", "value": operation},
                        {"key": "blocker_id", "value": f"cg21.workflow.{operation}.unsupported"},
                        {"key": "required_evidence", "value": "execution_certificate,native_io_certificate"},
                        {"key": "fallback_attempted", "value": "false"},
                        {"key": "external_engine_invoked", "value": "false"},
                        {"key": "runtime_execution", "value": "false"},
                        {"key": "data_read", "value": "false"},
                        {"key": "write_io", "value": "false"}
                    ],
                }))
                """
            )
        )
        workflow = (
            ShardLoomContext(ShardLoomClient(binary=binary))
            .read_csv("target/input.csv")
            .select("id", "label")
        )

        quality_report = workflow.data_quality_check("regex:label:[")
        quarantine_report = workflow.quarantine("target/bad.jsonl", "regex:label:[", check=False)

        self.assertIsInstance(quality_report, sl.UnsupportedWorkflowOperationReport)
        self.assertEqual(quality_report.operation, "data-quality")
        self.assertFalse(quality_report.fallback_attempted)
        self.assertFalse(quality_report.external_engine_invoked)
        self.assertIsInstance(quarantine_report, sl.UnsupportedWorkflowOperationReport)
        self.assertEqual(quarantine_report.operation, "quarantine")
        self.assertFalse(quarantine_report.fallback_attempted)
        self.assertFalse(quarantine_report.external_engine_invoked)

    def test_context_sql_schema_quality_helpers_invoke_sql_smoke(self) -> None:
        binary = self.fake_cli(
            textwrap.dedent(
                """
                import json, sys

                assert sys.argv[1] == "local-source-runtime", sys.argv
                assert sys.argv[3:] == [
                    "--output-format",
                    "inline-jsonl",
                    "--format",
                    "json",
                ], sys.argv
                base = "SELECT id,label,amount FROM 'target/input.csv' WHERE amount >= 10"
                if sys.argv[2] == base + " LIMIT 100":
                    result_jsonl = "{\\"id\\":1,\\"label\\":\\"alpha\\",\\"amount\\":10}\\n{\\"id\\":2,\\"label\\":null,\\"amount\\":15}\\n{\\"id\\":3,\\"label\\":\\"alpha\\",\\"amount\\":21}\\n"
                    row_count = "3"
                elif sys.argv[2] == base + " LIMIT 2":
                    result_jsonl = "{\\"id\\":1,\\"label\\":\\"alpha\\",\\"amount\\":10}\\n{\\"id\\":2,\\"label\\":null,\\"amount\\":15}\\n"
                    row_count = "2"
                else:
                    raise AssertionError(sys.argv)
                print(json.dumps({
                    "schema_version": "shardloom.output.v2",
                    "command": "local-source-runtime",
                    "status": "success",
                    "summary": "sql local source",
                    "human_text": "sql local source",
                    "fallback": {"attempted": False, "allowed": False, "engine": None, "reason": "disabled"},
                    "diagnostics": [],
                    "fields": [
                        {"key": "result_jsonl", "value": result_jsonl},
                        {"key": "output_row_count", "value": row_count},
                        {"key": "selected_row_count", "value": row_count},
                        {"key": "user_surface_runtime_scope", "value": "format_neutral_sql_frontend"},
                        {"key": "format_specific_boundary_scope", "value": "read_adapter_and_write_sink_only"},
                        {"key": "format_specific_compute_path", "value": "false"},
                        {"key": "fallback_attempted", "value": "false"},
                        {"key": "external_engine_invoked", "value": "false"},
                        {"key": "claim_gate_status", "value": "fixture_smoke_only"}
                    ],
                }))
                """
            )
        )
        ctx = ShardLoomContext(ShardLoomClient(binary=binary))
        workflow = ctx.sql(
            "SELECT id,label,amount FROM 'target/input.csv' WHERE amount >= 10"
        )

        schema = workflow.schema()
        described = workflow.describe_schema()
        validation = workflow.validate_schema(
            {"id": "int64", "label": "string", "amount": "int64"}
        )
        contract = workflow.schema_contract(
            {"id": "int64", "label": "string", "amount": "int64"}
        )
        quality_summary = workflow.data_quality_summary()
        quality_checks = workflow.data_quality_check(
            "not_null:id",
            "not_null:label",
            "unique:id",
            "unique:label",
        )
        profile = workflow.profile(limit=2)
        preview = workflow.preview(limit=2)
        head = workflow.head(limit=2)
        take = workflow.take(2)

        self.assertIsInstance(schema, sl.WorkflowSchemaReport)
        self.assertEqual(schema.schema_map, {"id": "int64", "label": "utf8", "amount": "int64"})
        self.assertFalse(schema.fallback_attempted)
        self.assertFalse(schema.external_engine_invoked)
        self.assertEqual(described.field_names, ("id", "label", "amount"))
        self.assertTrue(validation.valid)
        self.assertTrue(contract.valid)
        self.assertFalse(contract.fallback_attempted)
        self.assertFalse(contract.external_engine_invoked)
        self.assertEqual(quality_summary.null_counts, {"id": 0, "label": 1, "amount": 0})
        self.assertFalse(quality_checks.passed)
        by_check = {result.check: result for result in quality_checks.checks}
        self.assertFalse(by_check["not_null:label"].passed)
        self.assertFalse(by_check["unique:label"].passed)
        self.assertIsInstance(profile, sl.WorkflowProfileReport)
        self.assertEqual(profile.limit, 2)
        self.assertEqual(profile.row_count, 2)
        self.assertEqual(profile.null_counts, {"id": 0, "label": 1, "amount": 0})
        self.assertFalse(profile.fallback_attempted)
        self.assertFalse(profile.external_engine_invoked)
        for preview_report in (preview, head, take):
            self.assertEqual(preview_report.envelope.command, "local-source-runtime")
            self.assertEqual(preview_report.output_row_count, 2)
            self.assertFalse(preview_report.fallback_attempted)
            self.assertFalse(preview_report.external_engine_invoked)

    def test_sql_statement_with_limit_caps_existing_top_level_limit(self) -> None:
        from shardloom.query import _sql_statement_with_limit

        self.assertEqual(
            _sql_statement_with_limit("SELECT * FROM 'events.csv' LIMIT 10", 2),
            "SELECT * FROM 'events.csv' LIMIT 2",
        )
        self.assertEqual(
            _sql_statement_with_limit(
                "SELECT * FROM (SELECT * FROM 'events.csv' LIMIT 10) AS sub",
                2,
            ),
            "SELECT * FROM (SELECT * FROM 'events.csv' LIMIT 10) AS sub LIMIT 2",
        )

