    def test_local_csv_query_builder_melt_routes_through_prepared_vortex_melt(
        self,
    ) -> None:
        binary = self.fake_cli(
            textwrap.dedent(
                """
                import json
                import sys

                if sys.argv[1] == "workflow-unsupported-plan":
                    print(json.dumps({
                        "schema_version": "shardloom.output.v2",
                        "command": "workflow-unsupported-plan",
                        "status": "unsupported",
                        "summary": "unsupported",
                        "human_text": "unsupported",
                        "fallback": {"attempted": False, "allowed": False, "engine": None, "reason": "disabled"},
                        "diagnostics": [],
                        "fields": [
                            {"key": "workflow_operation", "value": sys.argv[2]},
                            {"key": "target_ref", "value": sys.argv[4]},
                            {"key": "blocker_id", "value": "cg21.workflow.melt.nested_or_broad_index_contract_missing"},
                            {"key": "fallback_attempted", "value": "false"},
                            {"key": "external_engine_invoked", "value": "false"},
                        ],
                    }))
                    sys.exit(1)

                raise AssertionError(f"unexpected fake CLI argv: {sys.argv[1:]}")
                """
            )
        )
        ctx = ShardLoomContext(ShardLoomClient(binary=binary))
        workflow = (
            ctx.read_csv(
                "target/input.csv",
                schema={
                    "id": "int64",
                    "amount_a": "int64",
                    "amount_b": "int64",
                },
            )
            .melt(
                id_vars=["id"],
                value_vars=["amount_a", "amount_b"],
                var_name="measure",
                value_name="amount",
            )
            .limit(4)
        )

        self.assertIsInstance(workflow, sl.LazyFrame)
        self.assertEqual(workflow.operations[-2].kind, "melt")
        payload = json.loads(workflow.operations[-2].values[0])
        self.assertEqual(payload["id_columns"], ["id"])
        self.assertEqual(payload["value_columns"], ["amount_a", "amount_b"])
        self.assertEqual(payload["variable_column"], "measure")
        self.assertEqual(payload["value_column"], "amount")

        report = workflow.collect()

        self.assertIsInstance(report, sl.VortexWorkflowExecutionReport)
        self.assertEqual(
            report.preparation_envelope.field("vortex_ingest_performed"), "true"
        )
        self.assertEqual(
            report.envelope.field("public_workflow_route_id"), "native_vortex_melt"
        )
        self.assertEqual(
            report.envelope.field("public_workflow_vortex_middle_status"),
            "native_vortex_primitive",
        )
        self.assertEqual(report.envelope.field("public_workflow_vortex_primitive"), "melt")
        self.assertEqual(
            report.envelope.field("public_workflow_vortex_columns"),
            "id,amount_a,amount_b",
        )
        self.assertEqual(
            report.envelope.field("public_workflow_vortex_source_order_limit"), "4"
        )
        self.assertEqual(
            report.envelope.field("public_workflow_vortex_melt_projection_present"), "true"
        )
        self.assertEqual(report.envelope.field("data_decoded"), "true")
        self.assertEqual(report.envelope.field("data_materialized"), "true")
        self.assertFalse(report.fallback_attempted)
        self.assertFalse(report.external_engine_invoked)

        inferred = (
            ctx.read_csv(
                "target/input.csv",
                schema={
                    "id": "int64",
                    "amount_a": "int64",
                    "amount_b": "int64",
                },
            )
            .select(["id", "amount_a", "amount_b"])
            .melt(
                id_vars="id",
                var_name="measure",
                value_name="amount",
                ignore_index=True,
            )
            .limit(4)
        )
        self.assertIsInstance(inferred, sl.LazyFrame)
        self.assertEqual(inferred.operations[-2].kind, "melt")
        inferred_payload = json.loads(inferred.operations[-2].values[0])
        self.assertEqual(inferred_payload["id_columns"], ["id"])
        self.assertEqual(inferred_payload["value_columns"], ["amount_a", "amount_b"])
        self.assertEqual(inferred_payload["variable_column"], "measure")
        self.assertEqual(inferred_payload["value_column"], "amount")

        indexed = (
            ctx.read_csv(
                "target/input.csv",
                schema={
                    "id": "int64",
                    "amount_a": "int64",
                    "label": "utf8",
                },
            )
            .select(["id", "amount_a", "label"])
            .melt(
                id_vars="id",
                value_vars=["amount_a", "label"],
                var_name="field",
                value_name="value",
                ignore_index=False,
            )
        )
        self.assertIsInstance(indexed, sl.UnsupportedWorkflowOperationReport)
        self.assertEqual(indexed.operation, "melt")

