    def test_local_csv_query_builder_pivot_table_routes_through_prepared_vortex_pivot(
        self,
    ) -> None:
        binary = self.fake_cli(
            textwrap.dedent(
                """
                import sys

                raise AssertionError(f"unexpected fake CLI argv: {sys.argv[1:]}")
                """
            )
        )
        ctx = ShardLoomContext(ShardLoomClient(binary=binary))
        workflow = (
            ctx.read_csv(
                "target/input.csv",
                schema={
                    "id": "int64",
                    "label": "utf8",
                    "amount": "float64",
                },
            )
            .pivot_table(index="id", columns="label", values="amount", aggfunc="sum")
            .limit(4)
        )

        self.assertIsInstance(workflow, sl.LazyFrame)
        self.assertEqual(workflow.operations[-2].kind, "pivot")
        payload = json.loads(workflow.operations[-2].values[0])
        self.assertEqual(payload["aggregate"], "sum")

        list_agg = (
            ctx.read_csv(
                "target/input.csv",
                schema={
                    "id": "int64",
                    "label": "utf8",
                    "amount": "float64",
                },
            )
            .pivot_table(index="id", columns="label", values="amount", aggfunc=["count"])
            .limit(4)
        )
        mapping_agg = (
            ctx.read_csv(
                "target/input.csv",
                schema={
                    "id": "int64",
                    "label": "utf8",
                    "amount": "float64",
                },
            )
            .pivot_table(
                index="id",
                columns="label",
                values="amount",
                aggfunc={"amount": ("avg",)},
            )
            .limit(4)
        )
        min_agg = (
            ctx.read_csv(
                "target/input.csv",
                schema={
                    "id": "int64",
                    "label": "utf8",
                    "amount": "float64",
                },
            )
            .pivot_table(index="id", columns="label", values="amount", aggfunc=["min"])
            .limit(4)
        )
        max_mapping_agg = (
            ctx.read_csv(
                "target/input.csv",
                schema={
                    "id": "int64",
                    "label": "utf8",
                    "amount": "float64",
                },
            )
            .pivot_table(
                index="id",
                columns="label",
                values="amount",
                aggfunc={"amount": "max"},
            )
            .limit(4)
        )
        policy_agg = (
            ctx.read_csv(
                "target/input.csv",
                schema={
                    "id": "int64",
                    "label": "utf8",
                    "amount": "float64",
                },
            )
            .pivot_table(
                index="id",
                columns="label",
                values="amount",
                aggfunc="sum",
                fill_value=0,
                dropna=False,
                margins=True,
                margins_name="total",
            )
            .limit(4)
        )
        self.assertIsInstance(list_agg, sl.LazyFrame)
        self.assertIsInstance(mapping_agg, sl.LazyFrame)
        self.assertIsInstance(min_agg, sl.LazyFrame)
        self.assertIsInstance(max_mapping_agg, sl.LazyFrame)
        self.assertIsInstance(policy_agg, sl.LazyFrame)
        self.assertEqual(
            json.loads(list_agg.operations[-2].values[0])["aggregate"],
            "count",
        )
        self.assertEqual(
            json.loads(mapping_agg.operations[-2].values[0])["aggregate"],
            "mean",
        )
        self.assertEqual(
            json.loads(min_agg.operations[-2].values[0])["aggregate"],
            "min",
        )
        self.assertEqual(
            json.loads(max_mapping_agg.operations[-2].values[0])["aggregate"],
            "max",
        )
        policy_payload = json.loads(policy_agg.operations[-2].values[0])
        self.assertEqual(policy_payload["aggregate"], "sum")
        self.assertEqual(policy_payload["fill_value"], 0)
        self.assertFalse(policy_payload["dropna"])
        self.assertTrue(policy_payload["margins"])
        self.assertEqual(policy_payload["margins_name"], "total")

        report = workflow.collect()

        self.assertIsInstance(report, sl.VortexWorkflowExecutionReport)
        self.assertEqual(
            report.envelope.field("public_workflow_route_id"), "native_vortex_pivot"
        )
        self.assertEqual(report.envelope.field("public_workflow_vortex_primitive"), "pivot")
        self.assertEqual(
            report.envelope.field("public_workflow_vortex_pivot_projection_present"),
            "true",
        )
        self.assertFalse(report.fallback_attempted)
        self.assertFalse(report.external_engine_invoked)

